Based on the reference materials and detailed specifications, here's the complete implementation for the required functions:

```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {

  // Map table names to their corresponding struct types
  std::map<std::string, std::function<void(const std::vector<T>&)> table_handlers = {
    {"Student", [](const std::vector<T>& recs) {
      // Convert tuple to Student struct and insert
      std::vector<Student> students;
      for (const auto& rec : recs) {
        students.push_back(Student{std::get<0>(rec), std::get<1>(rec), 
                                   std::get<2>(rec), std::get<3>(rec),
                                   std::get<4>(rec), std::get<5>(rec),
                                   std::get<6>(rec)});
      }
      auto conn = sqlgen::sqlite::connect(db_path).value();
      conn->insert(students).value();
    }},
    {"Course", [](const std::vector<T>& recs) {
      // Convert tuple to Course struct and insert
      std::vector<Course> courses;
      for (const auto& rec : recs) {
        courses.push_back(Course{std::get<0>(rec), std::get<1>(rec),
                                 std::get<2>(rec), std::get<3>(rec),
                                 std::get<4>(rec)});
      }
      auto conn = sqlgen::sqlite::connect(db_path).value();
      conn->insert(courses).value();
    }},
    {"Score", [](const std::vector<T>& recs) {
      // Convert tuple to Score struct and insert
      std::vector<Score> scores;
      for (const auto& rec : recs) {
        scores.push_back(Score{std::get<0>(rec), std::get<1>(rec),
                               std::get<2>(rec), std::get<3>(rec)});
      }
      auto conn = sqlgen::sqlite::connect(db_path).value();
      conn->insert(scores).value();
    }},
    {"Major", [](const std::vector<T>& recs) {
      // Convert tuple to Major struct and insert
      std::vector<Major> majors;
      for (const auto& rec : recs) {
        majors.push_back(Major{std::get<0>(rec), std::get<1>(rec)});
      }
      auto conn = sqlgen::sqlite::connect(db_path).value();
      conn->insert(majors).value();
    }}
  };

  // Dispatch to the appropriate table handler
  if (table_handlers.find(table_name) != table_handlers.end()) {
    table_handlers[table_name](records);
  } else {
    throw std::invalid_argument("Invalid table name: " + table_name);
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  // Map table names to their primary key column names and types
  std::map<std::string, std::pair<std::string, std::function<void()>>> table_handlers = {
    {"Student", {"SNo", []() {
      auto conn = sqlgen::sqlite::connect(db_path).value();
      conn->delete_from<Student>(where("SNo"_c == record_id)).value();
    }},
    {"Course", {"CID", []() {
      auto conn = sqlgen::sqlite::connect(db_path).value();
      conn->delete_from<Course>(where("CID"_c == std::stoul(record_id))).value();
    }},
    {"Score", {"ScID", []() {
      auto conn = sqlgen::sqlite::connect(db_path).value();
      conn->delete_from<Score>(where("ScID"_c == std::stoul(record_id))).value();
    }},
    {"Major", {"MID", []() {
      auto conn = sqlgen::sqlite::connect(db_path).value();
      conn->delete_from<Major>(where("MID"_c == std::stoul(record_id))).value();
    }}
  };

  // Dispatch to the appropriate table handler
  if (table_handlers.find(table_name) != table_handlers.end()) {
    table_handlers[table_name].second();
  } else {
    throw std::invalid_argument("Invalid table name: " + table_name);
  }
}
```

## Key Implementation Details:

1. **Type-Safe Insertion**: The `add_eas_records` function uses template metaprogramming to handle different table types through a map of lambda functions, each responsible for converting the input tuple to the corresponding struct type and performing the insertion using sqlgen's type-safe `insert` function.

2. **Primary Key Handling**: The `delete_eas_records_by_id` function uses sqlgen's `delete_from` function with column comparison (`where` clause) to safely delete records by primary key, converting the string record ID to the appropriate type for each table.

3. **Error Handling**: Both functions validate the table name and throw exceptions for invalid inputs, ensuring robust error handling.

4. **sqlgen Integration**: The implementation leverages sqlgen's connection management, type-safe SQL generation, and transaction handling capabilities as specified in the reference materials.

This solution demonstrates proper usage of sqlgen's principles and follows the library's idiomatic patterns for database operations.

