#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::optional<std::string> city;
};

struct Friendship {
  int user_id1;
  int user_id2;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> friendship_date;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen::literals;

  // Create SQLite connection
  auto conn = sqlgen::sqlite::connect(":memory:");

  // Write data to database
  sqlgen::write(conn, users);
  sqlgen::write(conn, friendships);

  // Define table aliases
  auto u1 = "u1"_t1;
  auto u2 = "u2"_t2;
  auto f1 = "f1"_t3;
  auto f2 = "f2"_t4;
  auto f3 = "f3"_t5;

  // Build the mutual friends query
  auto mutual_friends_query = sqlgen::select_from<User, "u1">(u1.username.as<"user1_name">(), u2.username.as<"user2_name">())
    | sqlgen::inner_join<Friendship, "f1">(u1.user_id == f1.user_id1)
    | sqlgen::inner_join<Friendship, "f2">(f1.user_id2 == f2.user_id1)
    | sqlgen::inner_join<User, "u2">(f2.user_id2 == u2.user_id)
    | sqlgen::where(u1.user_id < u2.user_id && sqlgen::exists(
        sqlgen::select_from<Friendship, "f3">()
        | sqlgen::where(f3.user_id1 == u1.user_id && f3.user_id2 == u2.user_id)
      ))
    | sqlgen::group_by(u1.user_id, u2.user_id)
    | sqlgen::having(sqlgen::count(f1.user_id2) > 0)
    | sqlgen::to<std::vector<FriendConnection>>;

  // Execute the query and return results
  return mutual_friends_query(conn).value();
}

}  // namespace analyze_social_network
```

