#include <unordered_map>

namespace update_inventory_stock {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int stock;
};

bool update_inventory_stock(const std::unordered_map<int, int>& received) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to database
  auto conn_result = sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }

  // Create table if it doesn't exist
  auto create_result = create_table<Product>(conn_result.value());
  if (!create_result) {
    return false;
  }

  // Start transaction
  auto transaction_result = begin_transaction(conn_result.value());
  if (!transaction_result) {
    return false;
  }
  auto transaction = transaction_result.value();

  // Iterate through received products and update stock using type-safe operations
  for (const auto& [product_id, quantity] : received) {
    // Build type-safe update statement
    auto update_stmt = update<Product>("stock"_c.set("stock"_c + quantity))
                     | where("product_id"_c == product_id);

    // Execute the update
    auto update_result = update_stmt(transaction);
    if (!update_result) {
      // Rollback transaction on failure
      rollback(transaction);
      return false;
    }
  }

  // Commit transaction if all updates succeeded
  auto commit_result = commit(transaction);
  return commit_result.has_value();
}

}  // namespace update_inventory_stock

